+    if (topic_name.rfind(prefix, 0) == 0 && topic_name.at(prefix.length()) == '/') {
+      return topic_name.substr(prefix.length());
+    }
+  }
+  return topic_name;
+}
+
+const std::vector<std::string> & _get_all_ros_prefixes()
+{
+  return _ros_prefixes;
